# Getting Started: OAuth2 Authentication Flow in React

## Prerequisites

Before you begin, make sure you have:

- Node.js (v16+) and npm installed
- A React app (v18+) initialized
- OAuth2 credentials from your provider (Client ID, Client Secret)
- Basic familiarity with React hooks and async/await

---

## Step 1: Install Required Dependencies

Open your terminal in the project root and install the necessary packages:

```bash
npm install axios @tanstack/react-query jwt-decode
```

| Package | Purpose |
|---|---|
| `axios` | HTTP requests to the auth server |
| `@tanstack/react-query` | Server state management & token refresh |
| `jwt-decode` | Decode JWT tokens without verification |

---

## Step 2: Configure Environment Variables

Create a `.env` file in your project root. **Never commit this file to version control.**

```bash
# .env
REACT_APP_AUTH_URL=https://your-auth-server.com/oauth2
REACT_APP_CLIENT_ID=your_client_id_here
REACT_APP_REDIRECT_URI=http://localhost:3000/callback
REACT_APP_SCOPE=openid profile email
REACT_APP_TOKEN_URL=https://your-auth-server.com/oauth2/token
```

Add `.env` to your `.gitignore`:

```bash
# .gitignore
.env
.env.local
```

> ⚠️ **Security Note:** Never expose your Client Secret in a React app. Store it server-side only. React apps use the **Authorization Code Flow with PKCE** to stay secure without a client secret.

---

## Step 3: Build the PKCE Helper Utilities

PKCE (Proof Key for Code Exchange) prevents authorization code interception attacks. Create a utilities file:

```javascript
// src/auth/pkce.js

/**
 * Generates a cryptographically random string for the PKCE code verifier
 */
export function generateCodeVerifier() {
  const array = new Uint8Array(64);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}

/**
 * Hashes the code verifier using SHA-256 to create the code challenge
 */
export async function generateCodeChallenge(verifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const digest = await crypto.subtle.digest("SHA-256", data);
  return base64UrlEncode(new Uint8Array(digest));
}

/**
 * Encodes a Uint8Array to a Base64 URL-safe string
 */
function base64UrlEncode(array) {
  return btoa(String.fromCharCode(...array))
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=/g, "");
}

/**
 * Generates a random state string to prevent CSRF attacks
 */
export function generateState() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}
```

---

## Step 4: Create the Auth Context

Set up a React context to manage auth state across your entire app:

```javascript
// src/auth/AuthContext.js
import { createContext, useContext, useState, useEffect, useCallback } from "react";
import { jwtDecode } from "jwt-decode";

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser]         = useState(null);
  const [accessToken, setAccessToken] = useState(null);
  const [isLoading, setIsLoading]   = useState(true);
  const [error, setError]       = useState(null);

  // Rehydrate auth state from sessionStorage on app load
  useEffect(() => {
    try {
      const storedToken = sessionStorage.getItem("access_token");
      if (storedToken) {
        const decoded = jwtDecode(storedToken);

        // Check if the token is still valid
        const isExpired = decoded.exp * 1000 < Date.now();
        if (!isExpired) {
          setAccessToken(storedToken);
          setUser(decoded);
        } else {
          sessionStorage.clear();
        }
      }
    } catch (err) {
      console.error("Failed to rehydrate auth state:", err);
      sessionStorage.clear();
    } finally {
      setIsLoading(false);
    }
  }, []);

  const saveTokens = useCallback((token) => {
    const decoded = jwtDecode(token);
    sessionStorage.setItem("access_token", token);
    setAccessToken(token);
    setUser(decoded);
  }, []);

  const logout = useCallback(() => {
    sessionStorage.clear();
    setAccessToken(null);
    setUser(null);
  }, []);

  const value = {
    user,
    accessToken,
    isLoading,
    error,
    setError,
    saveTokens,
    logout,
    isAuthenticated: !!accessToken,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}

// Custom hook for easy consumption
export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}
```

> 💡 **Storage Note:** `sessionStorage` is used here instead of `localStorage` to limit token exposure. Tokens are cleared when the browser tab closes. Evaluate your app's requirements and choose accordingly.

---

## Step 5: Build the Login Initiator

Create the component that kicks off the OAuth2 flow:

```javascript
// src/auth/useLogin.js
import { useCallback } from "react";
import { generateCodeVerifier, generateCodeChallenge, generateState } from "./pkce";

const AUTH_URL      = process.env.REACT_APP_AUTH_URL;
const CLIENT_ID     = process.env.REACT_APP_CLIENT_ID;
const REDIRECT_URI  = process.env.REACT_APP_REDIRECT_URI;
const SCOPE         = process.env.REACT_APP_SCOPE;

export function useLogin() {
  const login = useCallback(async () => {
    try {
      // 1. Generate PKCE values and state
      const codeVerifier    = generateCodeVerifier();
      const codeChallenge   = await generateCodeChallenge(codeVerifier);
      const state           = generateState();

      // 2. Persist verifier and state — needed in the callback step
      sessionStorage.setItem("pkce_code_verifier", codeVerifier);
      sessionStorage.setItem("oauth_state", state);

      // 3. Build the authorization URL
      const params = new URLSearchParams({
        response_type:          "code",
        client_id:              CLIENT_ID,
        redirect_uri:           REDIRECT_URI,
        scope:                  SCOPE,
        state:                  state,
        code_challenge:         codeChallenge,
        code_challenge_method:  "S256",
      });

      // 4. Redirect the user to the auth provider
      window.location.href = `${AUTH_URL}/authorize?${params.toString()}`;
    } catch (err) {
      console.error("Login initialization failed:", err);
    }
  }, []);

  return { login };
}
```

---

## Step 6: Handle the Callback

After login, the provider redirects back to your app with an authorization code. Handle it here:

```javascript
// src/pages/CallbackPage.jsx
import { useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { useAuth } from "../auth/AuthContext";

const TOKEN_URL    = process.env.REACT_APP_TOKEN_URL;
const CLIENT_ID    = process.env.REACT_APP_CLIENT_ID;
const REDIRECT_URI = process.env.REACT_APP_REDIRECT_URI;

export default function CallbackPage() {
  const { saveTokens, setError } = useAuth();
  const navigate     = useNavigate();
  const hasRun       = useRef(false); // Prevent double-execution in React StrictMode

  useEffect(() => {
    if (hasRun.current) return;
    hasRun.current = true;

    async function handleCallback() {
      const params = new URLSearchParams(window.location.search);
      const code   = params.get("code");
      const state  = params.get("state");
      const error  = params.get("error");

      // Handle provider-side errors
      if (error) {
        setError(`Auth provider error: ${error}`);
        navigate("/login");
        return;
      }

      // Validate the state parameter to prevent CSRF
      const savedState = sessionStorage.getItem("oauth_state");
      if (!state || state !== savedState) {
        setError("Invalid state parameter. Possible CSRF attack.");
        navigate("/login");
        return;
      }

      // Retrieve the stored PKCE code verifier
      const codeVerifier = sessionStorage.getItem("pkce_code_verifier");
      if (!codeVerifier) {
        setError("Missing PKCE verifier. Please log in again.");
        navigate("/login");
        return;
      }

      try {
        // Exchange the authorization code for tokens
        const response = await axios.post(
          TOKEN_URL,
          new URLSearchParams({
            grant_type:    "authorization_code",
            code,
            redirect_uri:  REDIRECT_URI,
            client_id:     CLIENT_ID,
            code_verifier: codeVerifier,
          }),
          { headers: { "Content-Type": "application/x-www-form-urlencoded" } }
        );

        const { access_token } = response.data;

        // Clean up temporary storage values
        sessionStorage.removeItem("pkce_code_verifier");
        sessionStorage.removeItem("oauth_state");

        // Save tokens and redirect to the app
        saveTokens(access_token);
        navigate("/dashboard");
      } catch (err) {
        const message = err.response?.data?.error_description || "Token exchange failed.";
        setError(message);
        navigate("/login");
      }
    }

    handleCallback();
  }, [navigate, saveTokens, setError]);

  return (
    <div role="status" aria-live="polite">
      <p>Completing sign-in, please wait...</p>
    </div>
  );
}
```

---

## Step 7: Protect Routes with a Guard Component

```javascript
// src/auth/ProtectedRoute.jsx
import { Navigate, Outlet } from "react-router-dom";
import { useAuth } from "./AuthContext";

export default function ProtectedRoute({ redirectTo = "/login" }) {
  const { isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    return <div role="status">Checking authentication...</div>;
  }

  return isAuthenticated
    ? <Outlet />
    : <Navigate to={redirectTo} replace />;
}
```

---

## Step 8: Wire Everything Together

```javascript
// src/App.jsx
import { BrowserRouter, Routes, Route } from "react-router-dom";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { AuthProvider } from "./auth/AuthContext";
import ProtectedRoute from "./auth/ProtectedRoute";
import LoginPage from "./pages/LoginPage";
import CallbackPage from "./pages/CallbackPage";
import Dashboard from "./pages/Dashboard";

const queryClient = new QueryClient();

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>
        <BrowserRouter>
          <Routes>
            {/* Public routes */}
            <Route path="/login"    element={<LoginPage />} />
            <Route path="/callback" element={<CallbackPage />} />

            {/* Protected routes */}
            <Route element={<ProtectedRoute />}>
              <Route path="/dashboard" element={<Dashboard />} />
              <Route path="/" element={<Dashboard />} />
            </Route>
          </Routes>
        </BrowserRouter>
      </AuthProvider>
    </QueryClientProvider>
  );
}
```

---

## Step 9: Build a Basic Login Page

```javascript
// src/pages/LoginPage.jsx
import { useLogin } from "../auth/useLogin";
import { useAuth } from "../auth/AuthContext";

export default function LoginPage() {
  const { login }  = useLogin();
  const { error }  = useAuth();

  return (
    <main>
      <h1>Welcome</h1>

      {error && (
        <div role="alert" style={{ color: "red" }}>
          {error}
        </div>
      )}

      <button onClick={login}>
        Sign in with OAuth2
      </button>
    </main>
  );
}
```

---

## Verification Checklist

Run your app with `npm start` and confirm each step works:

- [ ] Clicking **Sign in** redirects to your OAuth2 provider's login page
- [ ] After login, the provider redirects to `http://localhost:3000/callback`
- [ ] The callback page exchanges the code for a token successfully
- [ ] You are redirected to `/dashboard` after a successful login
- [ ] Refreshing the page keeps you logged in (token is rehydrated)
- [ ] Navigating to `/dashboard` while logged out redirects to `/login`
- [ ] Logging out clears the session and redirects correctly

---

## Common Errors & Fixes

| Error | Likely Cause | Fix |
|---|---|---|
| `redirect_uri_mismatch` | URI not registered with provider | Add exact URI to provider's allowed list |
| `invalid_grant` | Code already used or expired | Ensure callback only runs once (use `useRef`) |
| `invalid_state` | CSRF check failed | Check `sessionStorage` is accessible |
| Token not persisting | Storage type mismatch | Confirm read/write uses the same storage key |
| Blank callback page | StrictMode double-invoke | Use `useRef` guard as shown in Step 6 |

---

## Next Steps

Once your basic flow is working, consider these enhancements:

- **Token Refresh** — Use `refresh_token` grant to silently renew sessions
- **Axios Interceptors** — Automatically attach `Authorization: Bearer <token>` headers
- **Logout URL** — Redirect to the provider's logout endpoint to clear their session too
- **Role-based Access** — Read claims from the decoded JWT to gate features
- **Testing** — Mock `window.location` and `sessionStorage` in Jest for unit tests

# React Auth Context Provider for Next.js

## Overview

A robust authentication context that handles SSR/CSR hydration safely, provides typed access to auth state, and persists sessions via localStorage.

## File Structure

```
src/
├── contexts/
│   ├── AuthContext.tsx
│   └── AuthContext.test.tsx
├── hooks/
│   └── useAuth.ts
├── components/
│   └── AuthProvider.tsx
└── types/
    └── auth.ts
```

## Types

```typescript
// src/types/auth.ts
export interface User {
  id: string;
  email: string;
  name: string;
  role: 'admin' | 'user' | 'guest';
  avatarUrl?: string;
  metadata?: Record<string, unknown>;
}

export interface AuthTokens {
  accessToken: string;
  refreshToken: string;
  expiresAt: number; // Unix timestamp in ms
}

export interface AuthState {
  user: User | null;
  tokens: AuthTokens | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isHydrated: boolean; // Tracks SSR -> CSR hydration
  error: string | null;
}

export interface AuthContextValue extends AuthState {
  login: (credentials: LoginCredentials) => Promise<void>;
  logout: () => Promise<void>;
  register: (data: RegisterData) => Promise<void>;
  refreshSession: () => Promise<boolean>;
  clearError: () => void;
  updateUser: (updates: Partial<User>) => void;
}

export interface LoginCredentials {
  email: string;
  password: string;
  rememberMe?: boolean;
}

export interface RegisterData {
  email: string;
  password: string;
  name: string;
}

// Storage schema for validation
export interface PersistedAuthData {
  user: User;
  tokens: AuthTokens;
  persistedAt: number;
}
```

## Auth Context

```typescript
// src/contexts/AuthContext.tsx
'use client'; // Next.js App Router directive

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useReducer,
  useRef,
} from 'react';
import type {
  AuthContextValue,
  AuthState,
  AuthTokens,
  LoginCredentials,
  PersistedAuthData,
  RegisterData,
  User,
} from '@/types/auth';

// ─── Constants ───────────────────────────────────────────────────────────────

const STORAGE_KEY = 'app:auth' as const;
const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000; // Refresh 5 min before expiry
const MAX_STORAGE_AGE_MS = 30 * 24 * 60 * 60 * 1000; // 30 days

// ─── Initial State ────────────────────────────────────────────────────────────

const initialState: AuthState = {
  user: null,
  tokens: null,
  isAuthenticated: false,
  isLoading: false,
  isHydrated: false, // Always false on server
  error: null,
};

// ─── Reducer ──────────────────────────────────────────────────────────────────

type AuthAction =
  | { type: 'HYDRATE'; payload: { user: User; tokens: AuthTokens } | null }
  | { type: 'LOGIN_START' }
  | { type: 'LOGIN_SUCCESS'; payload: { user: User; tokens: AuthTokens } }
  | { type: 'LOGIN_FAILURE'; payload: string }
  | { type: 'LOGOUT' }
  | { type: 'REGISTER_START' }
  | { type: 'REGISTER_SUCCESS'; payload: { user: User; tokens: AuthTokens } }
  | { type: 'REGISTER_FAILURE'; payload: string }
  | { type: 'TOKEN_REFRESHED'; payload: AuthTokens }
  | { type: 'TOKEN_REFRESH_FAILED' }
  | { type: 'UPDATE_USER'; payload: Partial<User> }
  | { type: 'CLEAR_ERROR' };

function authReducer(state: AuthState, action: AuthAction): AuthState {
  switch (action.type) {
    case 'HYDRATE':
      return {
        ...state,
        isHydrated: true,
        user: action.payload?.user ?? null,
        tokens: action.payload?.tokens ?? null,
        isAuthenticated: action.payload !== null,
        isLoading: false,
      };

    case 'LOGIN_START':
    case 'REGISTER_START':
      return { ...state, isLoading: true, error: null };

    case 'LOGIN_SUCCESS':
    case 'REGISTER_SUCCESS':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: true,
        user: action.payload.user,
        tokens: action.payload.tokens,
        error: null,
      };

    case 'LOGIN_FAILURE':
    case 'REGISTER_FAILURE':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: false,
        user: null,
        tokens: null,
        error: action.payload,
      };

    case 'LOGOUT':
      return {
        ...initialState,
        isHydrated: true, // Keep hydrated after logout
      };

    case 'TOKEN_REFRESHED':
      return {
        ...state,
        tokens: action.payload,
        isAuthenticated: true,
      };

    case 'TOKEN_REFRESH_FAILED':
      return {
        ...initialState,
        isHydrated: true,
        error: 'Session expired. Please log in again.',
      };

    case 'UPDATE_USER':
      if (!state.user) return state;
      return {
        ...state,
        user: { ...state.user, ...action.payload },
      };

    case 'CLEAR_ERROR':
      return { ...state, error: null };

    default:
      return state;
  }
}

// ─── Storage Utilities ────────────────────────────────────────────────────────

const storage = {
  get(): PersistedAuthData | null {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return null;

      const data = JSON.parse(raw) as PersistedAuthData;

      // Validate shape
      if (!data.user?.id || !data.tokens?.accessToken || !data.persistedAt) {
        storage.clear();
        return null;
      }

      // Check storage age (separate from token expiry)
      const age = Date.now() - data.persistedAt;
      if (age > MAX_STORAGE_AGE_MS) {
        storage.clear();
        return null;
      }

      return data;
    } catch {
      storage.clear();
      return null;
    }
  },

  set(user: User, tokens: AuthTokens): void {
    try {
      const data: PersistedAuthData = {
        user,
        tokens,
        persistedAt: Date.now(),
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch (err) {
      // Handle QuotaExceededError gracefully
      console.warn('[Auth] Failed to persist auth state:', err);
    }
  },

  clear(): void {
    try {
      localStorage.removeItem(STORAGE_KEY);
    } catch {
      // Ignore
    }
  },
};

// ─── Mock API (Replace with your actual API calls) ────────────────────────────

const authApi = {
  async login(credentials: LoginCredentials): Promise<{ user: User; tokens: AuthTokens }> {
    // Replace with actual API call
    const response = await fetch('/api/auth/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(credentials),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message ?? 'Login failed');
    }

    return response.json();
  },

  async register(data: RegisterData): Promise<{ user: User; tokens: AuthTokens }> {
    const response = await fetch('/api/auth/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message ?? 'Registration failed');
    }

    return response.json();
  },

  async refresh(refreshToken: string): Promise<AuthTokens> {
    const response = await fetch('/api/auth/refresh', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ refreshToken }),
    });

    if (!response.ok) throw new Error('Token refresh failed');
    return response.json();
  },

  async logout(refreshToken: string): Promise<void> {
    await fetch('/api/auth/logout', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ refreshToken }),
    }).catch(() => {
      // Best-effort logout — don't block UI
    });
  },
};

// ─── Context ──────────────────────────────────────────────────────────────────

export const AuthContext = createContext<AuthContextValue | null>(null);

AuthContext.displayName = 'AuthContext';

// ─── Provider ─────────────────────────────────────────────────────────────────

interface AuthProviderProps {
  children: React.ReactNode;
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [state, dispatch] = useReducer(authReducer, initialState);
  const refreshTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isMountedRef = useRef(false);

  // ── Hydration: Read localStorage after mount (client-only) ──
  useEffect(() => {
    isMountedRef.current = true;
    const persisted = storage.get();

    if (!persisted) {
      dispatch({ type: 'HYDRATE', payload: null });
      return;
    }

    // Check if access token is still valid
    const isTokenExpired = persisted.tokens.expiresAt < Date.now();

    if (isTokenExpired) {
      // Try to refresh immediately
      authApi
        .refresh(persisted.tokens.refreshToken)
        .then((tokens) => {
          if (!isMountedRef.current) return;
          const refreshedTokens = { ...tokens };
          storage.set(persisted.user, refreshedTokens);
          dispatch({
            type: 'HYDRATE',
            payload: { user: persisted.user, tokens: refreshedTokens },
          });
        })
        .catch(() => {
          if (!isMountedRef.current) return;
          storage.clear();
          dispatch({ type: 'HYDRATE', payload: null });
        });
    } else {
      dispatch({
        type: 'HYDRATE',
        payload: { user: persisted.user, tokens: persisted.tokens },
      });
    }

    return () => {
      isMountedRef.current = false;
    };
  }, []);

  // ── Auto Token Refresh ────────────────────────────────────────
  useEffect(() => {
    if (!state.tokens || !state.isAuthenticated) return;

    const timeUntilRefresh =
      state.tokens.expiresAt - Date.now() - TOKEN_REFRESH_BUFFER_MS;

    if (timeUntilRefresh <= 0) return; // Will be handled by hydration

    refreshTimerRef.current = setTimeout(async () => {
      const success = await refreshSession();
      if (!success && isMountedRef.current) {
        dispatch({ type: 'TOKEN_REFRESH_FAILED' });
        storage.clear();
      }
    }, timeUntilRefresh);

    return () => {
      if (refreshTimerRef.current) {
